class Solution:
    def sort(self, sortResolutions: str) -> str:
        # 去掉首尾空白字符
        text = sortResolutions.strip()

        # 若输入为空，则直接返回空串
        if not text:
            return ""

        # 按空格切分出所有分辨率字符串
        items = text.split()

        arr = []
        for s in items:
            # 按 'x' 分割出宽和高
            w_str, h_str = s.split('x')
            w = int(w_str)
            h = int(h_str)

            # 判断清晰度等级，数值越大表示等级越高
            if w >= 3840 and h >= 2160:
                level = 3
            elif w >= 2560 and h >= 1440:
                level = 2
            elif w >= 1920 and h >= 1080:
                level = 1
            else:
                level = 0

            # 保存排序所需信息：原字符串、等级、面积、宽度
            arr.append((s, level, w * h, w))

        # 按题意排序：
        # 1. 清晰度等级从大到小
        # 2. 面积从大到小
        # 3. 宽从大到小
        arr.sort(key=lambda x: (-x[1], -x[2], -x[3]))

        # 拼接排序结果并返回
        return '"' + ' '.join(item[0] for item in arr) + '"'
```

```java
import java.util.*;

public class Solution {
    static class Node {
        String text;
        int level;
        long area;
        int width;

        Node(String text, int level, long area, int width) {
            this.text = text;
            this.level = level;
            this.area = area;
            this.width = width;
        }
    }

    public String sort(String sortResolutions) {
        // 去掉首尾空白字符
        String text = sortResolutions.trim();

        // 若输入为空，则直接返回空串
        if (text.isEmpty()) {
            return "";
        }

        // 按空格切分所有分辨率字符串
        String[] parts = text.split("\\s+");
        List<Node> list = new ArrayList<>();

        for (String s : parts) {
            // 按 'x' 分割出宽和高
            String[] wh = s.split("x");
            int w = Integer.parseInt(wh[0]);
            int h = Integer.parseInt(wh[1]);

            // 判断清晰度等级
            int level;
            if (w >= 3840 && h >= 2160) {
                level = 3;
            } else if (w >= 2560 && h >= 1440) {
                level = 2;
            } else if (w >= 1920 && h >= 1080) {
                level = 1;
            } else {
                level = 0;
            }

            // 保存排序所需信息
            list.add(new Node(s, level, 1L * w * h, w));
        }

        // 按题意排序
        list.sort((a, b) -> {
            if (a.level != b.level) return b.level - a.level;
            if (a.area != b.area) return Long.compare(b.area, a.area);
            if (a.width != b.width) return b.width - a.width;
            return 0;
        });

        // 拼接结果输出
        StringBuilder sb = new StringBuilder();
        sb.append('"');
        for (int i = 0; i < list.size(); i++) {
            if (i > 0) sb.append(' ');
            sb.append(list.get(i).text);
        }
        sb.append('"');
        return sb.toString();
    }
}
